advanced.DisableDatesUsingCustomize:
// JavaScript
import '@maersk-global/mds-components-core/mc-calendar';
const mcCalendar = document.querySelector('mc-calendar');
mcCalendar.customize = [
  { date: '${currentYear}-${currentMonthFormat}-05', disabled: true },
  { date: new Date(${currentYear}, ${currentMonthIndex}, 12), disabled: true },
  { date: { from: new Date(${currentYear}, ${currentMonthIndex}, 18), to: '${currentYear}-${currentMonthFormat}-22' }, disabled: true },
];

// HTML
<mc-calendar value="${currentYear}-${currentMonthFormat}-10"></mc-calendar>

advanced.DisableDatesUsingCallbackFunction:
// JavaScript
import '@maersk-global/mds-components-core/mc-calendar';
const mcCalendar = document.querySelector('mc-calendar');
mcCalendar.customize = [
  { date: (date) => date.getDay() === 6 || date.getDay() === 0, disabled: true },
];

// HTML
<mc-calendar value="${currentYear}-${currentMonthFormat}-10"></mc-calendar>

advanced.CustomisedAppearance:
// JavaScript
import '@maersk-global/mds-components-core/mc-calendar';

// CSS
mc-calendar::part(calendar) {
  padding: 16px;
}

// HTML
<mc-calendar customstyles="${customstyles}{color: green; font-weight: 700}"></mc-calendar>

advanced.FooterSlot:
// JavaScript
import '@maersk-global/mds-components-core/mc-calendar';

// HTML
<mc-calendar>
  <span class="mds-text--x-small-normal" slot="footer">Use arrow keys to navigate between days</span>
</mc-calendar>

advanced.DayIndicator:
// JavaScript
import '@maersk-global/mds-components-core/mc-calendar';
const mcCalendar = document.querySelector('mc-calendar');
mcCalendar.customize = [
  { date: (date) => date.getDay() === 6, indicatorAppearance: 'warning'},
  { date: '${currentYear}-${currentMonthFormat}-25', indicatorAppearance: 'success' },
  { date: '${currentYear}-${currentMonthFormat}-1', indicatorAppearance: 'error' },
  //custom CSS color
  { date: '${currentYear}-${currentMonthFormat}-15', indicatorAppearance: '#000000' },
];

// HTML
<mc-calendar value="${currentYear}-${currentMonthFormat}-10"></mc-calendar>
